/*
 * =======================================================================
 * cascaded_model_weights.h
 * وزن‌های کنترلر هوشمند RezaSeek — نسخه ۳.۰
 * تولیدشده توسط extract_cascaded_weights.py
 *
 * معماری: Input(7) -> Dense(64,ReLU) -> Dense(32,ReLU) -> Dense(16,ReLU) -> [D1(sig), D2(sig)]
 *
 * پارامتر: 3,154   Flash: 12.3 KB   RAM: ~512 B
 * =======================================================================
 */

