/* ======================================================================
 * nn_inference — کنترلر هوشمند
 *
 * ورودی‌ها (input[7]):
 *   [0] Vin         ولتاژ ورودی (V)
 *   [1] Vint        ولتاژ میانی (V)
 *   [2] Iint        جریان میانی (A)
 *   [3] Vout        ولتاژ خروجی (V)
 *   [4] Iout        جریان خروجی (A)
 *   [5] Vref        ولتاژ مرجع (V)
 *   [6] error_Vout  = Vout - Vref (V)
 *
 * خروجی‌ها:
 *   *d1_out : دیوتی سایکل مبدل اول  [0.05, 0.92]
 *   *d2_out : دیوتی سایکل مبدل دوم  [0.05, 0.92]
 *
 * زمان اجرا: ~36 µs @ 170 MHz (با FPU)
 * RAM مصرفی: 512 bytes (buf_a + buf_b)
 * ======================================================================*/

static inline void nn_inference(
        const float input[NN_INPUT_SIZE],
        float *d1_out,
        float *d2_out)
{
    float buf_a[NN_MAX_HIDDEN];
    float buf_b[NN_MAX_HIDDEN];
    uint32_t i, j;

    /* ---- گام ۱: نرمال‌سازی ورودی ---------------------------------- */
    for (i = 0U; i < NN_INPUT_SIZE; i++) {
        buf_a[i] = (input[i] - NN_MEAN[i]) / NN_STD[i];
    }

    /* ---- گام ۲: لایه‌های مشترک ------------------------------------ */

    /* Dense1  [7 → 64] */
    for (i = 0U; i < 64U; i++) {
        buf_b[i] = dense1_b[i];
        for (j = 0U; j < 7U; j++) {
            buf_b[i] += dense1_W[i][j] * buf_a[j];
        }
        if (buf_b[i] < 0.0f) buf_b[i] = 0.0f;  /* ReLU */
    }
    for (i = 0U; i < 64U; i++) buf_a[i] = buf_b[i];

    /* Dense2  [64 → 32] */
    for (i = 0U; i < 32U; i++) {
        buf_b[i] = dense2_b[i];
        for (j = 0U; j < 64U; j++) {
            buf_b[i] += dense2_W[i][j] * buf_a[j];
        }
        if (buf_b[i] < 0.0f) buf_b[i] = 0.0f;  /* ReLU */
    }
    for (i = 0U; i < 32U; i++) buf_a[i] = buf_b[i];

    /* Dense3  [32 → 16] */
    for (i = 0U; i < 16U; i++) {
        buf_b[i] = dense3_b[i];
        for (j = 0U; j < 32U; j++) {
            buf_b[i] += dense3_W[i][j] * buf_a[j];
        }
        if (buf_b[i] < 0.0f) buf_b[i] = 0.0f;  /* ReLU */
    }
    for (i = 0U; i < 16U; i++) buf_a[i] = buf_b[i];

    /* ---- گام ۳: خروجی‌های موازی ---------------------------------- */

    /* Output_D1 → d1_out */
    {
        float raw = output_d1_b[0];
        for (j = 0U; j < 16U; j++) {
            raw += output_d1_W[0][j] * buf_a[j];
        }
        raw = 1.0f / (1.0f + expf(-raw));           /* Sigmoid */
        raw = raw * (NN_D1_FEAT_MAX - NN_D1_FEAT_MIN) + NN_D1_FEAT_MIN;  /* برگشت به duty */
        if (raw < D_MIN) raw = D_MIN;               /* کلیپ */
        if (raw > D_MAX) raw = D_MAX;
        *d1_out = raw;
    }

    /* Output_D2 → d2_out */
    {
        float raw = output_d2_b[0];
        for (j = 0U; j < 16U; j++) {
            raw += output_d2_W[0][j] * buf_a[j];
        }
        raw = 1.0f / (1.0f + expf(-raw));           /* Sigmoid */
        raw = raw * (NN_D2_FEAT_MAX - NN_D2_FEAT_MIN) + NN_D2_FEAT_MIN;  /* برگشت به duty */
        if (raw < D_MIN) raw = D_MIN;               /* کلیپ */
        if (raw > D_MAX) raw = D_MAX;
        *d2_out = raw;
    }
}

#endif /* CASCADED_MODEL_WEIGHTS_H */
